import{_ as e,a as o,b as i,c as r,d as s,e as t,f as d,g as n}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as l,o as c,c as p,a2 as u}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"Índice distribuído federado","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/Other/federated-distributed-index.md","filePath":"pt-BR/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),m={name:"pt-BR/Other/federated-distributed-index.md"};function h(v,a,b,g,q,f){return c(),p("div",null,[...a[0]||(a[0]=[u('<h1 id="indice-distribuido-federado" tabindex="-1">Índice distribuído federado <a class="header-anchor" href="#indice-distribuido-federado" aria-label="Permalink to &quot;Índice distribuído federado&quot;">​</a></h1><p>O índice distribuído federado permite que vários sites ImgBed compartilhem listas de arquivos entre si.</p><p>Em termos simples:</p><ul><li>Você pode compartilhar algumas pastas do seu site com outras pessoas.</li><li>Pode entrar no nó de outra pessoa e sincronizar a lista compartilhada dela no seu painel.</li><li>Arquivos federados servem para navegar, buscar, pré-visualizar e copiar links. Eles não são reenviados para o seu armazenamento.</li></ul><h2 id="onde-configurar" tabindex="-1">Onde configurar <a class="header-anchor" href="#onde-configurar" aria-label="Permalink to &quot;Onde configurar&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configurações do sistema -&gt; Outras configurações -&gt; Índice distribuído federado</span></span></code></pre></div><p><img src="'+e+`" alt="Nó local" loading="lazy"></p><p>A página tem três abas:</p><table tabindex="0"><thead><tr><th>Aba</th><th>Uso</th></tr></thead><tbody><tr><td>Nó local</td><td>Configurar seu nó, domínio público, pastas compartilhadas e índice de saída</td></tr><tr><td>Nós que entrei</td><td>Gerenciar nós de outros sites que você acompanha</td></tr><tr><td>Solicitações ao meu nó</td><td>Gerenciar pedidos de outras pessoas para entrar no seu nó</td></tr></tbody></table><h2 id="configuracao-inicial" tabindex="-1">Configuração inicial <a class="header-anchor" href="#configuracao-inicial" aria-label="Permalink to &quot;Configuração inicial&quot;">​</a></h2><ol><li>Abra <code>Nó local</code>.</li><li>Ative <code>Habilitar</code>.</li><li>Escolha as pastas em <code>Pastas de sincronização</code>.</li><li>Clique em <code>Atualizar índice de saída</code>.</li><li>Se o ImgBed detectar mudança de domínio, confirme se o domínio atual é o domínio real de produção.</li></ol><p>Você pode escolher várias pastas. Se a lista ficar vazia, todas as pastas serão compartilhadas.</p><h2 id="no-local" tabindex="-1">Nó local <a class="header-anchor" href="#no-local" aria-label="Permalink to &quot;Nó local&quot;">​</a></h2><h3 id="dominio-publico" tabindex="-1">Domínio público <a class="header-anchor" href="#dominio-publico" aria-label="Permalink to &quot;Domínio público&quot;">​</a></h3><p>O domínio público é o endereço usado por outros nós para acessar seu site.</p><p>O ImgBed detecta isso automaticamente. Normalmente você não precisa digitar nada. Na primeira atualização do índice, ou após troca de domínio, ele pede confirmação.</p><h3 id="pastas-de-sincronizacao" tabindex="-1">Pastas de sincronização <a class="header-anchor" href="#pastas-de-sincronizacao" aria-label="Permalink to &quot;Pastas de sincronização&quot;">​</a></h3><p>Essas pastas definem quais arquivos serão compartilhados.</p><p>Exemplo:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>Nesse caso, outros nós verão apenas arquivos dentro desses dois diretórios.</p><h3 id="atualizar-indice-de-saida" tabindex="-1">Atualizar índice de saída <a class="header-anchor" href="#atualizar-indice-de-saida" aria-label="Permalink to &quot;Atualizar índice de saída&quot;">​</a></h3><p>Atualiza a lista de arquivos que outros nós podem sincronizar a partir do seu site.</p><p>Use quando:</p><ul><li>Ativar a federação pela primeira vez.</li><li>Enviar novos arquivos que deseja compartilhar.</li><li>Alterar as pastas compartilhadas.</li><li>Trocar o domínio público e precisar confirmar novamente.</li></ul><h2 id="entrar-em-outros-nos" tabindex="-1">Entrar em outros nós <a class="header-anchor" href="#entrar-em-outros-nos" aria-label="Permalink to &quot;Entrar em outros nós&quot;">​</a></h2><p><code>Nós que entrei</code> é onde você acompanha nós de outros sites ImgBed.</p><p><img src="`+o+'" alt="Nós que entrei" loading="lazy"></p><ol><li>Peça ao dono do outro nó um link de convite.</li><li>Cole o link no campo.</li><li>Clique em <code>Solicitar entrada</code>.</li><li>Aguarde a aprovação no painel da outra pessoa.</li></ol><p>Depois da aprovação, use <code>Atualizar índice de entrada</code> para sincronizar os arquivos compartilhados.</p><p>Se quiser atualizar apenas um nó, use <code>Atualizar índice</code> no cartão desse nó.</p><p><img src="'+i+'" alt="Atualizar índice" loading="lazy"></p><h2 id="gerenciar-solicitacoes-ao-seu-no" tabindex="-1">Gerenciar solicitações ao seu nó <a class="header-anchor" href="#gerenciar-solicitacoes-ao-seu-no" aria-label="Permalink to &quot;Gerenciar solicitações ao seu nó&quot;">​</a></h2><p><code>Solicitações ao meu nó</code> mostra quem quer entrar no seu nó.</p><p><img src="'+r+'" alt="Solicitações ao meu nó" loading="lazy"></p><p>Para gerar um convite, habilite o nó local, execute <code>Atualizar índice de saída</code> ao menos uma vez para confirmar o domínio público e clique em <code>Redefinir link de convite</code>.</p><p>Ao receber uma solicitação, você pode escolher:</p><table tabindex="0"><thead><tr><th>Ação</th><th>Resultado</th></tr></thead><tbody><tr><td>Aprovar</td><td>Permite que a outra parte sincronize sua lista compartilhada</td></tr><tr><td>Recusar</td><td>Não permite a entrada</td></tr><tr><td>Excluir</td><td>Remove um registro encerrado</td></tr><tr><td>Verificar status</td><td>Confere se a outra parte ainda mantém a relação</td></tr></tbody></table><p>Depois da aprovação, a outra parte ainda precisa atualizar o índice de entrada para ver seus arquivos.</p><p><img src="'+s+'" alt="Aprovar nó" loading="lazy"></p><h2 id="mensagens" tabindex="-1">Mensagens <a class="header-anchor" href="#mensagens" aria-label="Permalink to &quot;Mensagens&quot;">​</a></h2><p>Quando a relação já estiver aprovada, é possível usar <code>Mensagem</code> no cartão do nó.</p><p>As mensagens servem apenas para comunicação sobre a relação federada. Elas não alteram arquivos, tags, diretórios nem permissões.</p><p><img src="'+t+'" alt="Mensagens" loading="lazy"></p><h2 id="ver-arquivos-federados" tabindex="-1">Ver arquivos federados <a class="header-anchor" href="#ver-arquivos-federados" aria-label="Permalink to &quot;Ver arquivos federados&quot;">​</a></h2><p>Depois da sincronização, volte à lista de arquivos do painel. No topo, alterne entre arquivos locais e arquivos federados.</p><p>Arquivos federados não são locais: você pode visualizar, buscar, pré-visualizar e copiar links, mas não pode mover, excluir, alterar tags ou fazer backup deles a partir do seu site.</p><p><img src="'+d+'" alt="Vista no painel" loading="lazy"></p><h2 id="perguntas-comuns" tabindex="-1">Perguntas comuns <a class="header-anchor" href="#perguntas-comuns" aria-label="Permalink to &quot;Perguntas comuns&quot;">​</a></h2><h3 id="aparece-que-nao-existe-relacao" tabindex="-1">Aparece que não existe relação <a class="header-anchor" href="#aparece-que-nao-existe-relacao" aria-label="Permalink to &quot;Aparece que não existe relação&quot;">​</a></h3><p>Geralmente significa que a outra parte removeu seu registro. Nesse caso, envie uma nova solicitação.</p><p><img src="'+n+'" alt="Solicitar novamente" loading="lazy"></p><h3 id="entrei-no-no-mas-nao-vejo-arquivos" tabindex="-1">Entrei no nó, mas não vejo arquivos <a class="header-anchor" href="#entrei-no-no-mas-nao-vejo-arquivos" aria-label="Permalink to &quot;Entrei no nó, mas não vejo arquivos&quot;">​</a></h3><p>Confira:</p><ol><li>A outra parte aprovou sua solicitação.</li><li>A outra parte atualizou o índice de saída.</li><li>Você atualizou o índice de entrada.</li><li>As pastas sincronizadas da outra parte incluem os diretórios compartilhados.</li></ol>',55)])])}const A=l(m,[["render",h]]);export{x as __pageData,A as default};
